import React from 'react';
import { useNavigate } from 'react-router-dom';
import { LogOut, Home } from 'lucide-react';

export default function Dashboard() {
  const navigate = useNavigate();

  const menuItems = [
    { label: 'Profile', path: '/profile' },
    { label: 'Events', path: '/events' },
    { label: 'Network', path: '/network' },
    { label: 'Messages', path: '/messages' },
    { label: 'Jobs', path: '/jobs' },
    { label: 'Directory', path: '/directory' },
    { label: 'News', path: '/news' },
    { label: 'Settings', path: '/settings' },
  ];

  return (
    <div className="min-h-screen bg-gray-50">
      <nav className="bg-white shadow">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex justify-between items-center">
          <h1 className="text-2xl font-bold text-gray-900">Alumni Network</h1>
          <button onClick={() => navigate('/')} className="flex items-center gap-2 text-red-600 hover:text-red-700">
            <LogOut className="w-5 h-5" /> Logout
          </button>
        </div>
      </nav>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <h2 className="text-3xl font-bold text-gray-900 mb-8">Welcome to Alumni Dashboard</h2>
        
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          {menuItems.map((item) => (
            <button
              key={item.path}
              onClick={() => navigate(item.path)}
              className="bg-white rounded-lg shadow p-6 hover:shadow-lg transition text-left"
            >
              <Home className="w-8 h-8 text-blue-600 mb-2" />
              <h3 className="font-semibold text-gray-900">{item.label}</h3>
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}
